class Solution {
    public int minimumOperationsToMakeEqual(int x, int y) {
        int diff = Math.abs(x - y);
        int ops = 0;
        while (diff > 0) {
            if (diff % 11 == 0) {
                diff /= 11;
                ops++;
            } else if (diff % 5 == 0) {
                diff /= 5;
                ops++;
            } else if (diff > 0) {
                diff--;
                ops++;
            }
        }
        return ops;
    }
}
```

